let t='';try{t=$json.candidates?.[0]?.content?.parts?.[0]?.text||$json.body?.candidates?.[0]?.content?.parts?.[0]?.text||'';}catch(e){}
let o={};try{const m=t.match(/\{[\s\S]*\}/);if(m)o=JSON.parse(m[0]);}catch(e){}
const action=['call','text'].includes(String(o.action))?o.action:'none';
const personSafe=String(o.person||'').replace(/[^A-Za-z0-9 ]/g,'').trim();
const src=$('Get message').item.json;
return [{json:{
  content:String(o.content||'Untitled task').slice(0,400),
  description:String(o.description||''),
  due_string:String(o.due_string||''),
  label:String(o.label||''),
  priority:(parseInt(o.priority)>=1&&parseInt(o.priority)<=4)?parseInt(o.priority):1,
  action, personSafe, chatId:src.chatId, updateId:src.updateId }}];

const t=$('Parse task').item.json;
const tel=$json.phone_tel, raw=$json.phone_raw;
const esc=s=>String(s).replace(/@/g,'\\@').replace(/#/g,'\\#');
let desc=t.description||'';
let actionNote='';
if(tel && (t.action==='call'||t.action==='text')){
  const links='📞 [Call](tel:'+tel+')  •  💬 [Text](sms:'+tel+')';
  desc=(desc?desc+'\n\n':'')+links;
  actionNote=' 📞 '+(raw||tel);
} else if(t.action!=='none' && t.personSafe && !tel){
  actionNote=' ⚠️ no contact "'+t.personSafe+'" found';
}
const task={content:esc(t.content).slice(0,400)};
if(desc) task.description=desc.slice(0,9000);
if(t.due_string) task.due_string=t.due_string;
if(t.priority>1) task.priority=t.priority;
if(t.label){const l=t.label.replace(/[^A-Za-z0-9]+/g,'_').replace(/^_+|_+$/g,'');if(l)task.labels=[l];}
const confirm='✅ Added: '+t.content
 +(t.due_string?' 📅 '+t.due_string:'')
 +(t.label?' 🏷️ '+t.label:'')
 +(t.priority>1?' ❗p'+(5-t.priority):'')
 +actionNote;
return [{json:{todoistBody:JSON.stringify(task),chatId:t.chatId,updateId:t.updateId,confirm}}];
